## Objective
Create the canonical TypeScript types and Zod validation schemas for the Hypothesis type and related structures.

## Implementation Details

### File Location
`apps/web/src/lib/hypothesis.ts`

### Schema Definition
```typescript
import { z } from 'zod';

export const HypothesisStateSchema = z.enum([
  'proposed',
  'active',
  'refined',
  'killed',
  'validated',
  'dormant'
]);

export const HypothesisOriginSchema = z.enum([
  'proposed',
  'third_alternative',
  'refinement'
]);

export const HypothesisSchema = z.object({
  id: z.string().regex(/^H-[A-Z0-9]+-\d{3}$/),
  statement: z.string().min(10).max(500),
  origin: HypothesisOriginSchema,
  parentId: z.string().optional(),
  sessionId: z.string(),
  proposedBy: z.string().optional(),
  state: HypothesisStateSchema,
  createdAt: z.string().datetime(),
  updatedAt: z.string().datetime(),
  notes: z.string().optional(),
  tags: z.array(z.string()).optional(),
});

export type Hypothesis = z.infer<typeof HypothesisSchema>;
export type HypothesisState = z.infer<typeof HypothesisStateSchema>;
export type HypothesisOrigin = z.infer<typeof HypothesisOriginSchema>;
```

### ID Generation
```typescript
export function generateHypothesisId(sessionId: string, sequence: number): string {
  const paddedSeq = sequence.toString().padStart(3, '0');
  return `H-${sessionId}-${paddedSeq}`;
}
```

### Validation Functions
```typescript
export function validateHypothesis(data: unknown): ValidationResult {
  const result = HypothesisSchema.safeParse(data);
  if (result.success) {
    return { valid: true, errors: [] };
  }
  return {
    valid: false,
    errors: result.error.errors.map(e => `${e.path.join('.')}: ${e.message}`),
  };
}
```

